1	import { createCipheriv, createDecipheriv, randomBytes } from 'node:crypto';
2	import { PluginError } from '@ax/core';
3	
4	const PLUGIN_NAME = '@ax/credentials';
5	const ALGO = 'aes-256-gcm';
6	const IV_LEN = 12;
7	const TAG_LEN = 16;
8	const KEY_LEN = 32;
9	
10	export function encryptWithKey(key: Buffer, plaintext: string): Uint8Array {
11	  if (key.length !== KEY_LEN) {
12	    throw new PluginError({
13	      code: 'invalid-key',
14	      plugin: PLUGIN_NAME,
15	      message: `encryption key must be ${KEY_LEN} bytes`,
16	    });
17	  }
18	  const iv = randomBytes(IV_LEN);
19	  const cipher = createCipheriv(ALGO, key, iv, { authTagLength: TAG_LEN });
20	  const ct = Buffer.concat([cipher.update(plaintext, 'utf8'), cipher.final()]);
21	  const tag = cipher.getAuthTag();
22	  return new Uint8Array(Buffer.concat([iv, ct, tag]));
23	}
24	
25	export function decryptWithKey(key: Buffer, blob: Uint8Array): string {
26	  if (key.length !== KEY_LEN) {
27	    throw new PluginError({
28	      code: 'invalid-key',
29	      plugin: PLUGIN_NAME,
30	      message: `decryption key must be ${KEY_LEN} bytes`,
31	    });
32	  }
33	  if (blob.length < IV_LEN + TAG_LEN) {
34	    throw new PluginError({
35	      code: 'invalid-ciphertext',
36	      plugin: PLUGIN_NAME,
37	      message: 'ciphertext too short',
38	    });
39	  }
40	  const buf = Buffer.from(blob);
41	  const iv = buf.subarray(0, IV_LEN);
42	  const tag = buf.subarray(buf.length - TAG_LEN);
43	  const ct = buf.subarray(IV_LEN, buf.length - TAG_LEN);
44	  // Pin authTagLength so a forged blob can't trick us into accepting a
45	  // shorter-than-expected tag (semgrep gcm-no-tag-length / sg.run/NbGG1).
46	  // We only ever produce 16-byte tags, so anything else is hostile.
47	  const decipher = createDecipheriv(ALGO, key, iv, { authTagLength: TAG_LEN });
48	  decipher.setAuthTag(tag);
49	  try {
50	    return Buffer.concat([decipher.update(ct), decipher.final()]).toString('utf8');
51	  } catch {
52	    throw new PluginError({
53	      code: 'decrypt-failed',
54	      plugin: PLUGIN_NAME,
55	      message: 'authentication tag mismatch',
56	    });
57	  }
58	}
59	
