86	async function startCapturingUpstream(
87	  ca: CAKeyPair,
88	): Promise<{ port: number; captured: CapturedRequest; gotRequest: Promise<void>; close: () => Promise<void> }> {
89	  const leaf = generateDomainCert('127.0.0.1', ca);
90	  const captured: CapturedRequest = { authorization: undefined, body: '' };
91	  let resolveReq!: () => void;
92	  const gotRequest = new Promise<void>((resolve) => {
93	    resolveReq = resolve;
94	  });
95	
96	  const server: TLSServer = tlsCreate({ key: leaf.key, cert: leaf.cert }, (sock) => {
97	    let buf = '';
98	    sock.on('data', (d) => {
99	      buf += d.toString('utf8');
100	      const headerEnd = buf.indexOf('\r\n\r\n');
101	      if (headerEnd === -1) return;
102	      const header = buf.slice(0, headerEnd);
103	      const lines = header.split('\r\n');
104	      let contentLength = 0;
105	      for (const line of lines.slice(1)) {
106	        const idx = line.indexOf(':');
107	        if (idx === -1) continue;
108	        const k = line.slice(0, idx).trim().toLowerCase();
109	        const v = line.slice(idx + 1).trim();
110	        if (k === 'authorization') captured.authorization = v;
111	        if (k === 'content-length') contentLength = parseInt(v, 10);
112	      }
113	      const bodyStart = headerEnd + 4;
114	      if (buf.length - bodyStart >= contentLength) {
115	        captured.body = buf.slice(bodyStart, bodyStart + contentLength);
116	        sock.write('HTTP/1.1 200 OK\r\nContent-Length: 2\r\nConnection: close\r\n\r\nOK');
117	        sock.end();
118	        resolveReq();
119	      }
120	    });
121	    sock.on('error', () => { /* ignored — abort-side errors expected */ });
122	  });
123	
124	  const port = await new Promise<number>((r) =>
125	    server.listen(0, '127.0.0.1', () => r((server.address() as { port: number }).port)),
126	  );
127	  return {
128	    port,
129	    captured,
130	    gotRequest,
131	    close: () => new Promise<void>((r) => server.close(() => r())),
132	  };
133	}
