137	/**
138	 * TLS upstream signed by the proxy's CA. The proxy adds its CA to the
139	 * outbound trust store, so the chain validates without
140	 * `rejectUnauthorized: false`.
141	 */
142	async function startCapturingTLSUpstream(ca: CAKeyPair): Promise<{
143	  port: number;
144	  captured: CapturedTLS;
145	  gotRequest: Promise<void>;
146	  close: () => Promise<void>;
147	}> {
148	  const leaf = generateDomainCert('127.0.0.1', ca);
149	  const captured: CapturedTLS = { authorization: undefined, body: '' };
150	  let resolveReq!: () => void;
151	  const gotRequest = new Promise<void>((resolve) => {
152	    resolveReq = resolve;
153	  });
154	  const server: TLSServer = tlsCreate({ key: leaf.key, cert: leaf.cert }, (sock) => {
155	    let buf = '';
156	    sock.on('data', (d) => {
