    const bus = await bootBus();
    const a = await bus.call<unknown, { codeVerifier: string; state: string }>(
      'credentials:login:anthropic-oauth',
      ctx(),
      {},
    );
    const b = await bus.call<unknown, { codeVerifier: string; state: string }>(
