    const out = await bus.call<
      { code: string; codeVerifier: string; state: string },
      { payload: Uint8Array; expiresAt: number; kind: string }
    >('credentials:exchange:anthropic-oauth', ctx(), {
      code: 'auth-code-xyz',
      codeVerifier: 'verifier-abc',
      state: 'state-123',
    });
