// ── credentials login ────────────────────────────────────────────────

interface LoginOutput {
  authorizeUrl: string;
  codeVerifier: string;
  state: string;
}
interface ExchangeOutput {
  payload: Uint8Array;
  expiresAt: number;
  kind: 'anthropic-oauth';
}

async function runLoginCommand(
  opts: RunCredentialsOptions,
  out: (line: string) => void,
  err: (line: string) => void,
): Promise<number> {
  const provider = opts.argv[1];
  if (provider !== 'anthropic') {
    err(USAGE);
    return 2;
  }
  const ref = opts.argv[2] ?? DEFAULT_OAUTH_REF;

  const bus = new HookBus();
  let handle;
  try {
    handle = await bootstrap({
      bus,
      plugins: [
        createStorageSqlitePlugin({ databasePath: opts.sqlitePath ?? DEFAULT_SQLITE_PATH }),
        createCredentialsStoreDbPlugin(),
        createCredentialsPlugin(),
        createCredentialsAnthropicOauthPlugin(),
      ],
      config: {},
    });
  } catch (e) {
    if (e instanceof PluginError) {
      err(`error: ${e.message}`);
      return 1;
    }
    err('error: unexpected failure');
    return 1;
  }

  try {
    // 1. Build the authorize URL + PKCE verifier + state.
    let login: LoginOutput;
    try {
      login = await bus.call<{ redirectUri: string }, LoginOutput>(
        'credentials:login:anthropic-oauth',
        makeAgentContext({ sessionId: 'cli', agentId: 'cli', userId: CLI_USER_ID }),
        { redirectUri: OAUTH_REDIRECT_URI },
      );
    } catch (e) {
      err(`error: ${(e as Error).message}`);
      return 1;
    }

    // 2. Stand up the redirect listener. Bind on the fixed port — Anthropic's
    //    whitelisted redirect_uri is :1455. EADDRINUSE means another instance
    //    is mid-flow or some other service holds the port; fail clearly.
    let server: Server;
    try {
      server = await startRedirectListener(login.state, login.codeVerifier);
    } catch (e) {
      err(`error: ${(e as Error).message}`);
      return 1;
    }

    // 3. Open the browser, then await the callback.
    out('Opening browser to authorize Anthropic OAuth.');
    out('If the browser does not open, visit:');
    out(`  ${login.authorizeUrl}`);
    try {
      (opts.openBrowserImpl ?? openBrowser)(login.authorizeUrl);
    } catch (e) {
      // Don't abort — the user can still paste the URL manually.
      err(`warn: failed to launch browser (${(e as Error).message})`);
    }

    let code: string;
    try {
      code = await waitForCallback(server, login.state);
    } catch (e) {
      err(`error: ${(e as Error).message}`);
      return 1;
    } finally {
      server.close();
    }

    // 4. Exchange the code for a token blob.
    let exchanged: ExchangeOutput;
    try {
      exchanged = await bus.call<
        { code: string; codeVerifier: string; state: string; redirectUri: string },
        ExchangeOutput
      >(
        'credentials:exchange:anthropic-oauth',
        makeAgentContext({ sessionId: 'cli', agentId: 'cli', userId: CLI_USER_ID }),
        {
          code,
          codeVerifier: login.codeVerifier,
          state: login.state,
          redirectUri: OAUTH_REDIRECT_URI,
        },
      );
    } catch (e) {
      err(`error: ${(e as Error).message}`);
      return 1;
    }

    // 5. Stash the blob via credentials:set.
    try {
      await bus.call(
        'credentials:set',
        makeAgentContext({ sessionId: 'cli', agentId: 'cli', userId: CLI_USER_ID }),
        {
          ref,
          userId: CLI_USER_ID,
          kind: exchanged.kind,
          payload: exchanged.payload,
          expiresAt: exchanged.expiresAt,
        },
      );
    } catch (e) {
      err(`error: ${(e as Error).message}`);
      return 1;
    }

    out(`Anthropic OAuth credential stored as ref='${ref}'`);
    return 0;
  } finally {
    await handle.shutdown();
  }
}

interface PendingCallback {
  resolve: (code: string) => void;
  reject: (err: Error) => void;
  expectedState: string;
  /** True iff a callback request has been received — guards double-resolve. */
  done: boolean;
}

function startRedirectListener(
  expectedState: string,
  // codeVerifier is not used in the listener — accepted purely so callers
  // signal that BOTH halves of the PKCE flow are owned by the same caller.
  // Kept here as a marker; the listener doesn't actually need it.
  _codeVerifier: string,
): Promise<Server> {
  return new Promise((resolve, reject) => {
    const server = createServer();
    server.on('error', (e: NodeJS.ErrnoException) => {
      if (e.code === 'EADDRINUSE') {
        reject(
          new Error(
            `port ${OAUTH_REDIRECT_PORT} is in use — another OAuth flow may be running`,
          ),
        );
        return;
      }
      reject(e);
    });
    server.listen(OAUTH_REDIRECT_PORT, '127.0.0.1', () => {
      // Sanity: verify the address actually bound.
      const addr = server.address() as AddressInfo | null;
      if (addr === null || addr.port !== OAUTH_REDIRECT_PORT) {
        server.close();
        reject(new Error('redirect listener failed to bind 127.0.0.1:1455'));
        return;
      }
      resolve(server);
    });
    void expectedState; // captured by waitForCallback below
  });
}

function waitForCallback(server: Server, expectedState: string): Promise<string> {
  return new Promise<string>((resolve, reject) => {
    const pending: PendingCallback = {
      resolve,
      reject,
      expectedState,
      done: false,
    };
    const onRequest = (req: IncomingMessage, res: ServerResponse): void => {
      // Only the /callback path is meaningful — the browser may also probe
      // /favicon.ico etc.
      const url = new URL(req.url ?? '/', OAUTH_REDIRECT_URI);
      if (url.pathname !== '/callback') {
        res.writeHead(404, { 'content-type': 'text/plain' });
        res.end('not found');
        return;
      }
      if (pending.done) {
        // Late retry — already resolved/rejected.
        res.writeHead(409, { 'content-type': 'text/plain' });
        res.end('already processed');
        return;
      }
      const code = url.searchParams.get('code');
      const state = url.searchParams.get('state');
      const errorParam = url.searchParams.get('error');
      if (errorParam !== null) {
        pending.done = true;
        res.writeHead(200, { 'content-type': 'text/html' });
        res.end(
          '<html><body><h2>Authorization failed</h2><p>You can close this tab and re-run <code>ax-next credentials login anthropic</code>.</p></body></html>',
        );
        pending.reject(new Error(`OAuth error from Anthropic: ${errorParam}`));
        return;
      }
      if (state !== expectedState) {
        pending.done = true;
        res.writeHead(400, { 'content-type': 'text/html' });
        res.end('<html><body><h2>State mismatch</h2></body></html>');
        pending.reject(new Error('OAuth state mismatch — possible CSRF; aborting'));
        return;
      }
      if (code === null || code === '') {
        pending.done = true;
        res.writeHead(400, { 'content-type': 'text/html' });
        res.end('<html><body><h2>Missing code</h2></body></html>');
        pending.reject(new Error('redirect missing authorization code'));
        return;
      }
      pending.done = true;
      res.writeHead(200, { 'content-type': 'text/html' });
      res.end(
        '<html><body><h2>Authorization successful!</h2><p>You can close this tab and return to the terminal.</p></body></html>',
      );
      pending.resolve(code);
    };
    server.on('request', onRequest);

    const timer = setTimeout(() => {
      if (pending.done) return;
      pending.done = true;
      reject(new Error(`OAuth flow timed out after ${OAUTH_TIMEOUT_MS / 1000}s`));
    }, OAUTH_TIMEOUT_MS);
    timer.unref();
  });
}

