    const stderrLines: string[] = [];
    const code = await runCredentialsCommand({
      argv: ['login'],
      stdin: stdinFromString(''),
      stdout: () => {},
      stderr: (l) => stderrLines.push(l),
      sqlitePath: join(tmp, 'db.sqlite'),
